→    # Build code context\n   121→    code_context = \"\"\n   122→    for file_info in code_files:\n   123→        code_context += f\"\\nFile: {file_info['path']}\\n\"\n   124→        code_context += f\"```{language}\\n{file_info['content']}\\n```\\n\"\n   125→    \n   126→    # Create messages for OpenAI\n   127→    messages = [\n   128→        {\n   129→            \"role\": \"system\",\n   130→            \"content\": \"You are an expert code transformation assistant. Provide clear, working code transformations based on the requirements.\"\n   131→        },\n   132→        {\n   133→            \"role\": \"user\",\n   134→            \"content\": f\"{prompt}\\n\\nHere is the code to transform:\\n{code_context}\"\n   135→        }\n   136→    ]\n   137→    \n   138→    print(f\"Calling OpenAI API with model {model}...\")\n   139→    \n   140→    try:\n   141→        # Call OpenAI API\n   142→        response = client.chat.completions.create(\n   143→            model=model,\n   144→            messages=messages,\n   145→            temperature=temperature,\n   146→            max_tokens=max_tokens,\n   147→            top_p=0.9,\n   148→            frequency_penalty=0.0,\n   149→            presence_penalty=0.0\n   150→        )\n   151→        \n   152→        # Extract transformed code\n   153→        transformed_content = response.choices[0].message.content\n   154→        \n   155→        # Save transformed code\n   156→        with open('/workspace/transformed.txt', 'w') as f:\n   157→            f.write(transformed_content)\n   158→        \n   159→        # Create metadata\n   160→        metadata = {\n   161→            'job_id': job_id,\n   162→            'model': model,\n   163→            'provider': 'openai',\n   164→            'language': language,\n   165→            'temperature': temperature,\n   166→            'max_tokens': max_tokens,\n   167→            'usage': {\n   168→                'prompt_tokens': response.usage.prompt_tokens,\n   169